/**
 * Reads chezmoi source config files and injects two auto-generated sections:
 *   - A "My configuration" Markdown table into docs/chezmoi.md
 *   - A machine-readable TOML block into .github/copilot-instructions.md
 *
 * Injection targets are HTML comment markers:
 *   <!-- BEGIN CHEZMOI-SETUP --> ... <!-- END CHEZMOI-SETUP -->
 *
 * Run: npm run chezmoi:sync
 */

import { existsSync, readFileSync, writeFileSync } from "node:fs";
import { join } from "node:path";
import { fileURLToPath } from "node:url";

const repoRoot = fileURLToPath(new URL("..", import.meta.url));

// ---------------------------------------------------------------------------
// Read source files
// ---------------------------------------------------------------------------

const chezmoiRoot = readFileSync(join(repoRoot, ".chezmoiroot"), "utf8").trim();
const tomlTmpl = readFileSync(
	join(repoRoot, "home", ".chezmoi.toml.tmpl"),
	"utf8",
);

// ---------------------------------------------------------------------------
// Parse .chezmoi.toml.tmpl
// ---------------------------------------------------------------------------

// sourceDir — personal machine: joinPath .chezmoi.homeDir "<rel-path>"
const sourceDirMatch = tomlTmpl.match(
	/joinPath\s+\.chezmoi\.homeDir\s+"([^"]+)"/,
);
const sourceDir = sourceDirMatch ? `~/${sourceDirMatch[1]}` : "(unknown)";

// [edit] command + args
const editSection = tomlTmpl.match(/\[edit\](.*?)(?=\n\[)/s)?.[0] ?? "";
const editCmd = editSection.match(/command\s*=\s*"([^"]+)"/)?.[1] ?? "";
const editArgs = parseTomlStringArray(
	editSection.match(/args\s*=\s*(\[[^\]]*\])/)?.[1],
);
const editor = [editCmd, ...editArgs].join(" ");

// [diff] command + args
const diffSection = tomlTmpl.match(/\[diff\](.*?)(?=\n\[)/s)?.[0] ?? "";
const diffCmd = diffSection.match(/command\s*=\s*"([^"]+)"/)?.[1] ?? "";
const diffArgs = parseTomlStringArray(
	diffSection.match(/args\s*=\s*(\[[^\]]*\])/)?.[1],
);
const diffTool = [diffCmd, ...diffArgs].join(" ");

// [[textconv]] — first entry only
const textconvSection =
	tomlTmpl.match(/\[\[textconv\]\](.*?)(?=\n\[|$)/s)?.[0] ?? "";
const textconvPattern =
	textconvSection.match(/pattern\s*=\s*"([^"]+)"/)?.[1] ?? "";
const textconvCmd = textconvSection.match(/command\s*=\s*"([^"]+)"/)?.[1] ?? "";
const textconvArgs = parseTomlStringArray(
	textconvSection.match(/args\s*=\s*(\[[^\]]*\])/)?.[1],
);
const textconvValue = [textconvCmd, ...textconvArgs].join(" ");

// ---------------------------------------------------------------------------
// Detect non-default paths from repo structure
// ---------------------------------------------------------------------------

const configDir = join(repoRoot, "home", "private_dot_config");

const gitConfig = existsSync(join(configDir, "private_git"))
	? "~/.config/git/config"
	: "~/.gitconfig";

const zshConfig = existsSync(join(configDir, "zsh")) ? "~/.config/zsh" : "~/";

const homebrewScript =
	"home/.chezmoiscripts/darwin/run_once_before_install-packages-darwin.sh.tmpl";
const homebrewPath = existsSync(join(repoRoot, homebrewScript))
	? homebrewScript
	: "(not found)";

// ---------------------------------------------------------------------------
// Build the injected content for each file
// ---------------------------------------------------------------------------

const markdownTable = `\
## My configuration

> Auto-generated by \`npm run chezmoi:sync\` \u2014 do not edit manually.

| Setting | Default | Yours |
| --- | --- | --- |
| Source directory | \`$XDG_DATA_HOME/chezmoi\` | \`${sourceDir}\` |
| Source root | (repo root) | \`${chezmoiRoot}/\` (\`.chezmoiroot\`) |
| Config file | \`$XDG_CONFIG_HOME/chezmoi/chezmoi.toml\` | same |
| Editor | \`$EDITOR\` | \`${editor}\` |
| Diff tool | built-in | \`${diffTool}\` |
| Git config | \`~/.gitconfig\` | \`$XDG_CONFIG_HOME/git/config\` |
| Zsh config dir | \`~/\` | \`$ZDOTDIR\` (\`${zshConfig}\`) |`;

const tomlBlock = `\
\`\`\`toml
# Auto-generated by \`npm run chezmoi:sync\` \u2014 do not edit manually.

[chezmoi]
source_dir  = "${sourceDir}"   # personal; work: prompted interactively
source_root = "${chezmoiRoot}"                            # .chezmoiroot
config_file = "~/.config/chezmoi/chezmoi.toml" # $XDG_CONFIG_HOME/chezmoi/chezmoi.toml
editor      = "${editor}"
diff_tool   = "${diffTool}"

[chezmoi.paths]
git_config = "${gitConfig}"            # $XDG_CONFIG_HOME/git/config
zsh_config = "${zshConfig}"                   # $ZDOTDIR
homebrew   = "${homebrewPath}"

[chezmoi.textconv]
"${textconvPattern}" = "${textconvValue}"
\`\`\``;

// ---------------------------------------------------------------------------
// Inject into files
// ---------------------------------------------------------------------------

injectSection(join(repoRoot, "docs", "chezmoi.md"), markdownTable);

injectSection(join(repoRoot, ".github", "copilot-instructions.md"), tomlBlock);

console.log("chezmoi:sync — done.");

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function parseTomlStringArray(raw) {
	if (!raw) return [];
	return [...raw.matchAll(/"([^"]+)"/g)].map((m) => m[1]);
}

function injectSection(filePath, content) {
	const BEGIN = "<!-- BEGIN CHEZMOI-SETUP -->";
	const END = "<!-- END CHEZMOI-SETUP -->";
	const source = readFileSync(filePath, "utf8");
	const start = source.indexOf(BEGIN);
	const end = source.indexOf(END);
	if (start === -1 || end === -1) {
		throw new Error(
			`Markers not found in ${filePath}. Add <!-- BEGIN CHEZMOI-SETUP --> and <!-- END CHEZMOI-SETUP -->.`,
		);
	}
	const updated =
		source.slice(0, start + BEGIN.length) +
		"\n\n" +
		content +
		"\n\n" +
		source.slice(end);
	if (updated === source) {
		console.log(`  unchanged: ${filePath}`);
		return;
	}
	writeFileSync(filePath, updated, "utf8");
	console.log(`  updated: ${filePath}`);
}
